"use strict";const REQUEST_CUSTOMER_PORTAL_URL='https://api.cryptomator.org/stripe/request_customer_portal.php';class CustomerPortal{constructor(a,b,c){this._form=a,this._feedbackData=b,this._submitData=c}request(){if(!$(this._form)[0].checkValidity()){$(this._form).find(':input').addClass('show-invalid');return}this._feedbackData.inProgress=!0,this._feedbackData.errorMessage='',this._feedbackData.success=!1,$.ajax({url:REQUEST_CUSTOMER_PORTAL_URL,type:'POST',data:this._submitData}).done(a=>{this.onRequestSucceeded()}).fail(a=>{this.onRequestFailed(a.responseJSON?.message||'Requesting supporter certificate failed.')})}onRequestFailed(a){this._feedbackData.success=!1,this._feedbackData.inProgress=!1,this._feedbackData.errorMessage=a}onRequestSucceeded(){this._feedbackData.success=!0,this._feedbackData.inProgress=!1,this._feedbackData.errorMessage=''}}